            const response = await fetch(`${API_BASE_URL}/api/auth/pending`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

            console.log('Pending users response status:', response.status);
            
            if (response.ok) {
                const data = await response.json();
                console.log('✅ Pending users data:', data);
                setPendingUsers(data.users || []);
            } else {
                console.error('❌ Failed to fetch pending users:', response.statusText);
            }
        } catch (error) {
            console.error('❌ Error fetching pending users:', error);
        }
    };

    const fetchApplicationSubmissions = async (token) => {
        try {
            console.log('📝 Fetching applications...');
            // Try multiple endpoints to ensure we get the data
            const endpoints = [
                `${API_BASE_URL}/api/applications`,
                `${API_BASE_URL}/api/application`
            ];

            for (const endpoint of endpoints) {
                try {
                    const response = await fetch(endpoint, {
                        headers: {
                            'Authorization': `Bearer ${token}`,
                            'Content-Type': 'application/json'
                        }
                    });

                    console.log(`Applications response from ${endpoint}:`, response.status);

                    if (response.ok) {
                        const data = await response.json();
                        console.log('✅ Applications data:', data);
                        
                        // Handle different response structures
                        const applications = data.applications || data.data || data || [];
                        setApplicationSubmissions(applications);
                        
                        setDashboardData(prev => ({
                            ...prev,
                            admin: {
                                ...prev.admin,
                                pendingApplications: applications.filter(app => 
                                    app.status === 'pending' || !app.status
                                ).length || 0
                            }
                        }));
                        return; // Success, exit loop
                    }
                } catch (endpointError) {
                    console.log(`Endpoint ${endpoint} failed:`, endpointError.message);
                }
            }
            console.error('❌ All application endpoints failed');
        } catch (error) {
            console.error('❌ Error fetching applications:', error);
        }
    };

    const fetchContactSubmissions = async (token) => {
        try {
            console.log('📝 Fetching contacts...');
            const response = await fetch(`${API_BASE_URL}/api/contact`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

