    const handleUserApproval = async (userId, approve) => {
        const token = localStorage.getItem('authToken');
        try {
            console.log(`${approve ? '✅ Approving' : '❌ Rejecting'} user:`, userId);
            const endpoint = approve ? 'approve' : 'reject';
            const method = approve ? 'PUT' : 'DELETE';
            
            const response = await fetch(`${API_BASE_URL}/api/auth/${endpoint}/${userId}`, {
                method,
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

            if (response.ok) {
                console.log(`✅ User ${approve ? 'approved' : 'rejected'} successfully`);
                await fetchPendingUsers(token);
                await fetchAllUsers(token);
            } else {
                console.error(`❌ Failed to ${approve ? 'approve' : 'reject'} user:`, response.statusText);
            }
        } catch (error) {
            console.error(`❌ Error ${approve ? 'approving' : 'rejecting'} user:`, error);
        }
    };

    const handleContactAction = async (contactId, action) => {
        const token = localStorage.getItem('authToken');
        try {
            console.log(`📧 Setting contact ${contactId} status to:`, action);
            const response = await fetch(`${API_BASE_URL}/api/contact/${contactId}/status`, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ status: action })
            });

            if (response.ok) {
                console.log(`✅ Contact status updated to ${action}`);
                await fetchContactSubmissions(token);
            } else {
                console.error(`❌ Failed to update contact status:`, response.statusText);
            }
        } catch (error) {
            console.error(`❌ Error updating contact status:`, error);
        }
    };

    const handleApplicationAction = async (applicationId, action) => {
