    // FIXED: Enhanced useEffect with better error handling and logging
    useEffect(() => {
        const checkAuth = async () => {
            console.log('🔐 Checking authentication...');
            const token = localStorage.getItem('authToken');
            
            if (!token) {
                console.log('❌ No token found, redirecting to login');
                history.push('/');
                return;
            }

            try {
                console.log('🔍 Verifying token...');
                const response = await fetch(`${API_BASE_URL}/api/auth/me`, {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json'
                    }
                });

                console.log('Auth response status:', response.status);

                if (!response.ok) {
                    throw new Error('Token invalid');
                }

                const data = await response.json();
                const userData = data.user;
                console.log('✅ User authenticated:', userData);

                setUser({
                    id: userData.id,
                    email: userData.email,
                    firstName: userData.firstName,
                    lastName: userData.lastName,
                    role: userData.role,
                    name: `${userData.firstName} ${userData.lastName}`.trim() || userData.email?.split('@')[0] || 'User',
                    isApproved: userData.isApproved
                });

                localStorage.setItem('userRole', userData.role);
                localStorage.setItem('userEmail', userData.email);
                localStorage.setItem('userName', `${userData.firstName} ${userData.lastName}`.trim());

                // FIXED: Enhanced admin data fetching with better error handling
                if (userData.role === 'admin') {
                    console.log('👨‍💼 Admin detected, fetching admin data...');
                    try {
                        await Promise.allSettled([
                            fetchPendingUsers(token),
                            fetchContactSubmissions(token),
                            fetchApplicationSubmissions(token),
                            fetchAllUsers(token)
                        ]);
                        console.log('✅ All admin data fetch attempts completed');
                    } catch (adminError) {
                        console.error('❌ Error fetching admin data:', adminError);
                    }
                }

            } catch (error) {
                console.error('❌ Auth check failed:', error);
                localStorage.clear();
                history.push('/');
                return;
            }

            setIsLoading(false);
        };

        checkAuth();
